class CustomHPOStrategy:
    """Surrogate-assisted ASHA (MF-SMAC)."""

    def __init__(self, seed: int = 42):
        self.seed = seed
        self.rng = np.random.RandomState(seed)
        self.f_levels = [0.11, 0.33, 1.0]
        self.eta = 3

    def _hash_cfg(self, config):
        return str(sorted(config.items()))

    def _encode(self, config, space):
        vec = []
        for p in space.params:
            val = config[p.name]
            if p.type == "categorical":
                idx = p.choices.index(val)
                vec.append(idx / max(len(p.choices) - 1, 1))
            elif p.type in ("float", "int"):
                if p.log_scale:
                    v = (np.log(val) - np.log(p.low)) / (np.log(p.high) - np.log(p.low))
                else:
                    v = (val - p.low) / (p.high - p.low)
                vec.append(float(np.clip(v, 0, 1)))
        return np.array(vec)

    def suggest(
        self,
        space: SearchSpace,
        history: List[Trial],
        budget_left: int,
    ) -> Tuple[Dict[str, Any], float]:
        import math
        from sklearn.ensemble import RandomForestRegressor

        # 1. Group history by level
        level_histories = {f: [] for f in self.f_levels}
        for t in history:
            closest_f = min(self.f_levels, key=lambda f: abs(f - t.budget))
            level_histories[closest_f].append(t)

        # 2. Check for promotions (top-down)
        for i in range(len(self.f_levels) - 2, -1, -1):
            f_curr = self.f_levels[i]
            f_next = self.f_levels[i+1]

            curr_hist = level_histories[f_curr]
            next_hist = level_histories[f_next]

            if not curr_hist:
                continue

            next_hashes = {self._hash_cfg(t.config) for t in next_hist}
            eligible = [t for t in curr_hist if self._hash_cfg(t.config) not in next_hashes]

            if eligible:
                sorted_curr = sorted(curr_hist, key=lambda x: x.score, reverse=True)
                n_promote = max(1, math.ceil(len(curr_hist) / self.eta))
                top_configs = sorted_curr[:n_promote]
                top_hashes = {self._hash_cfg(t.config) for t in top_configs}

                promotable = [t for t in eligible if self._hash_cfg(t.config) in top_hashes]
                if promotable:
                    best_promotable = max(promotable, key=lambda x: x.score)
                    return best_promotable.config.copy(), f_next

        # 3. No promotions, sample new config at the lowest level
        if len(history) < 5:
            return space.sample_uniform(self.rng), self.f_levels[0]

        # Use Random Forest BO to suggest new configuration
        X_train = []
        y_train = []
        for t in history:
            row = list(self._encode(t.config, space))
            row.append(t.budget)
            X_train.append(row)
            y_train.append(t.score)

        rf = RandomForestRegressor(n_estimators=50, random_state=self.seed)
        rf.fit(X_train, y_train)

        high_scores = [t.score for t in history if abs(t.budget - 1.0) < 1e-3]
        best_high = max(high_scores) if high_scores else max(y_train)

        candidates = []
        for _ in range(100):
            candidates.append(space.sample_uniform(self.rng))

        top_history = sorted(history, key=lambda t: t.score, reverse=True)[:3]
        for t in top_history:
            for _ in range(33):
                mutated = t.config.copy()
                n_mut = self.rng.randint(1, max(2, space.dim // 2 + 1))
                params_to_mut = self.rng.choice(space.params, n_mut, replace=False)
                for p in params_to_mut:
                    if p.type == "categorical":
                        mutated[p.name] = self.rng.choice(p.choices)
                    elif p.type == "float":
                        if p.log_scale:
                            val = np.log(mutated[p.name])
                            val += self.rng.randn() * (np.log(p.high) - np.log(p.low)) * 0.1
                            mutated[p.name] = float(np.clip(np.exp(val), p.low, p.high))
                        else:
                            val = mutated[p.name]
                            val += self.rng.randn() * (p.high - p.low) * 0.1
                            mutated[p.name] = float(np.clip(val, p.low, p.high))
                    elif p.type == "int":
                        if p.log_scale:
                            val = np.log(mutated[p.name])
                            val += self.rng.randn() * (np.log(p.high) - np.log(p.low)) * 0.1
                            mutated[p.name] = int(round(np.clip(np.exp(val), p.low, p.high)))
                        else:
                            val = mutated[p.name]
                            val += self.rng.randn() * (p.high - p.low) * 0.1
                            mutated[p.name] = int(round(np.clip(val, p.low, p.high)))
                candidates.append(mutated)

        X_cands = []
        for c in candidates:
            row = list(self._encode(c, space))
            row.append(1.0)
            X_cands.append(row)

        X_cands = np.array(X_cands)
        preds = np.array([tree.predict(X_cands) for tree in rf.estimators_])
        mean_pred = preds.mean(axis=0)
        std_pred = preds.std(axis=0)

        with np.errstate(divide='ignore', invalid='ignore'):
            z = (mean_pred - best_high) / (std_pred + 1e-9)
            ei = (mean_pred - best_high) * scipy_norm.cdf(z) + std_pred * scipy_norm.pdf(z)
        ei[std_pred == 0.0] = 0.0

        best_idx = int(np.argmax(ei))
        return candidates[best_idx], self.f_levels[0]
